import { useState } from "react";
import toast from "react-hot-toast";
import { useAuth } from "../../context/AuthContext";
import { Avatar, StatusBadge, PriorityBadge, Tag } from "../common/UI";
import { isOverdue, formatDate, STATUS_LABELS } from "../../utils/constants";
import api from "../../utils/api";

export default function TaskCard({ task, onEdit, onDelete, onRefresh }) {
  const { user } = useAuth();
  const [updating, setUpdating] = useState(false);
  const overdue = isOverdue(task.dueDate, task.status);

  const isSenior  = ["admin", "sub_admin", "team_lead"].includes(user.role);
  const isAssignee = task.assignedTo?._id === user._id || task.assignedTo === user._id;
  const isAssigner = task.assignedBy?._id === user._id || task.assignedBy === user._id;
  const canEdit   = isSenior || isAssigner;
  const canStatus = isAssignee || canEdit;

  const handleStatusChange = async (e) => {
    const newStatus = e.target.value;
    setUpdating(true);
    try {
      await api.put(`/tasks/${task._id}`, { status: newStatus, statusNote: `Changed to ${STATUS_LABELS[newStatus]}` });
      toast.success("Status updated!");
      onRefresh();
    } catch (err) {
      toast.error(err.response?.data?.message || "Failed to update status");
    } finally {
      setUpdating(false);
    }
  };

  const handleDelete = async () => {
    if (!window.confirm("Delete this task? This cannot be undone.")) return;
    try {
      await api.delete(`/tasks/${task._id}`);
      toast.success("Task deleted");
      onRefresh();
    } catch (err) {
      toast.error(err.response?.data?.message || "Failed to delete task");
    }
  };

  return (
    <div
      className="card card-hover"
      style={{
        borderColor: overdue ? "#FEE2E2" : undefined,
        background: overdue ? "#FFFAFA" : "#fff",
        position: "relative",
        overflow: "hidden",
      }}
    >
      {/* Priority accent line */}
      <div style={{
        position: "absolute", top: 0, left: 0, right: 0, height: 3, borderRadius: "12px 12px 0 0",
        background: { low: "#10B981", medium: "#F59E0B", high: "#F97316", urgent: "#EF4444" }[task.priority] || "#6366F1",
      }} />

      {/* Header */}
      <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", marginBottom: 10, paddingTop: 4 }}>
        <h3 style={{ fontSize: 14, fontWeight: 700, color: "var(--gray-900)", lineHeight: 1.4, flex: 1, marginRight: 8 }}>
          {task.title}
        </h3>
        <div style={{ display: "flex", gap: 4, flexShrink: 0 }}>
          {canEdit && (
            <button className="btn btn-icon btn-sm" onClick={() => onEdit(task)} title="Edit task">✏️</button>
          )}
          {(isSenior || isAssigner) && (
            <button className="btn btn-icon btn-sm" onClick={handleDelete} title="Delete task" style={{ background: "#FEF2F2" }}>🗑️</button>
          )}
        </div>
      </div>

      {/* Description */}
      {task.description && (
        <p style={{ fontSize: 12, color: "var(--gray-400)", lineHeight: 1.6, marginBottom: 10 }}>
          {task.description.slice(0, 100)}{task.description.length > 100 ? "…" : ""}
        </p>
      )}

      {/* Badges */}
      <div style={{ display: "flex", flexWrap: "wrap", gap: 5, marginBottom: 10 }}>
        <StatusBadge status={task.status} />
        <PriorityBadge priority={task.priority} />
        {overdue && (
          <span className="badge" style={{ background: "#FEF2F2", color: "#DC2626" }}>⚠ Overdue</span>
        )}
      </div>

      {/* Tags */}
      {task.tags?.length > 0 && (
        <div style={{ display: "flex", flexWrap: "wrap", gap: 4, marginBottom: 10 }}>
          {task.tags.map((t) => <Tag key={t} label={t} />)}
        </div>
      )}

      {/* Assignee + Due Date */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", borderTop: "1px solid var(--gray-100)", paddingTop: 10, marginBottom: 10 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
          <Avatar user={task.assignedTo} size={24} />
          <div>
            <div style={{ fontSize: 10, color: "var(--gray-400)" }}>Assigned to</div>
            <div style={{ fontSize: 11, fontWeight: 600, color: "var(--gray-700)" }}>{task.assignedTo?.name || "—"}</div>
          </div>
        </div>
        <div style={{ textAlign: "right" }}>
          <div style={{ fontSize: 10, color: "var(--gray-400)" }}>Due date</div>
          <div style={{ fontSize: 11, fontWeight: 600, color: overdue ? "var(--danger)" : "var(--gray-700)" }}>
            {formatDate(task.dueDate)}
          </div>
        </div>
      </div>

      {/* Team */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
        <span style={{ fontSize: 11, color: "var(--gray-400)" }}>📂 {task.team}</span>
        {task.assignedBy && (
          <span style={{ fontSize: 11, color: "var(--gray-400)" }}>
            by {task.assignedBy?.name?.split(" ")[0]}
          </span>
        )}
      </div>

      {/* Status quick update */}
      {canStatus && (
        <select
          value={task.status}
          onChange={handleStatusChange}
          disabled={updating}
          style={{
            fontSize: 12, padding: "6px 10px", border: "1.5px solid var(--gray-200)",
            borderRadius: 8, background: updating ? "var(--gray-50)" : "#fff", cursor: "pointer",
          }}
        >
          {Object.entries(STATUS_LABELS).map(([k, v]) => (
            <option key={k} value={k}>{v}</option>
          ))}
        </select>
      )}
    </div>
  );
}
